@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<div class="@CssClass" @attributes="AdditionalAttributes">
    @* Source panel *@
    <div class="flex-1 border border-border/40 rounded-lg overflow-hidden">
        <div class="px-3 py-2 border-b border-border/40 bg-muted/30">
            <div class="flex items-center justify-between">
                <label class="flex items-center gap-2 cursor-pointer">
                    @if (ShowSelectAll)
                    {
                        <Checkbox Checked="@SourceAllSelected" IsIndeterminate="@SourcePartiallySelected"
                                  CheckedChanged="ToggleSelectAllSource"
                                  AriaLabel="@L["Transfer.SelectAll"]" />
                    }
                    <span class="text-sm font-medium">@(SourceTitle ?? L["Transfer.SourceHeader"])</span>
                </label>
                <span class="text-xs text-muted-foreground">@_selectedSource.Count / @(SourceItems?.Count ?? 0)</span>
            </div>
        </div>
        @if (ShowSearch)
        {
            <div class="px-2 py-1.5 border-b border-border/40">
                <input type="text" placeholder="@L["Combobox.SearchPlaceholder"]"
                       class="flex h-7 w-full rounded-md border border-input bg-transparent px-2 py-1 text-xs placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring"
                       value="@_sourceSearch"
                       @oninput="OnSourceSearch" />
            </div>
        }
        <div class="max-h-64 overflow-y-auto p-1">
            @if (FilteredSourceItems is { Count: > 0 })
            {
                @foreach (var item in FilteredSourceItems)
                {
                    <label @key="item.Value" class="@ItemRowClass(item.Disabled)">
                        <Checkbox Checked="@_selectedSource.Contains(item.Value)" Disabled="@item.Disabled" CheckedChanged="b => ToggleSourceItem(item.Value, b)" />
                        <span class="truncate">@item.Label</span>
                    </label>
                }
            }
            else
            {
                <div class="text-center text-xs text-muted-foreground py-4">@L["Transfer.NoItems"]</div>
            }
        </div>
    </div>

    @* Transfer buttons *@
    <div class="flex flex-col items-center justify-center gap-1.5">
        <button type="button" class="@ButtonClass" @onclick="MoveToTarget" disabled="@(_selectedSource.Count == 0)"
                aria-label="@L["Transfer.MoveRight"]" title="@L["Transfer.MoveRight"]">
            <Blazicon Svg="Lucide.ChevronRight" class="h-4 w-4" />
        </button>
        <button type="button" class="@ButtonClass" @onclick="MoveToSource" disabled="@(_selectedTarget.Count == 0)"
                aria-label="@L["Transfer.MoveLeft"]" title="@L["Transfer.MoveLeft"]">
            <Blazicon Svg="Lucide.ChevronLeft" class="h-4 w-4" />
        </button>
    </div>

    @* Target panel *@
    <div class="flex-1 border border-border/40 rounded-lg overflow-hidden">
        <div class="px-3 py-2 border-b border-border/40 bg-muted/30">
            <div class="flex items-center justify-between">
                <label class="flex items-center gap-2 cursor-pointer">
                    @if (ShowSelectAll)
                    {
                        <Checkbox Checked="@TargetAllSelected" IsIndeterminate="@TargetPartiallySelected"
                                  CheckedChanged="ToggleSelectAllTarget"
                                  AriaLabel="@L["Transfer.SelectAll"]" />
                    }
                    <span class="text-sm font-medium">@(TargetTitle ?? L["Transfer.TargetHeader"])</span>
                </label>
                <span class="text-xs text-muted-foreground">@_selectedTarget.Count / @(TargetItems?.Count ?? 0)</span>
            </div>
        </div>
        @if (ShowSearch)
        {
            <div class="px-2 py-1.5 border-b border-border/40">
                <input type="text" placeholder="@L["Combobox.SearchPlaceholder"]"
                       class="flex h-7 w-full rounded-md border border-input bg-transparent px-2 py-1 text-xs placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring"
                       value="@_targetSearch"
                       @oninput="OnTargetSearch" />
            </div>
        }
        <div class="max-h-64 overflow-y-auto p-1">
            @if (FilteredTargetItems is { Count: > 0 })
            {
                @foreach (var item in FilteredTargetItems)
                {
                    <label @key="item.Value" class="@ItemRowClass(item.Disabled)">
                        <Checkbox Checked="@_selectedTarget.Contains(item.Value)" Disabled="@item.Disabled" CheckedChanged="b => ToggleTargetItem(item.Value, b)" />
                        <span class="truncate">@item.Label</span>
                    </label>
                }
            }
            else
            {
                <div class="text-center text-xs text-muted-foreground py-4">@L["Transfer.NoItems"]</div>
            }
        </div>
    </div>
</div>

@code {
    [Parameter] public List<TransferItem>? SourceItems { get; set; }
    [Parameter] public EventCallback<List<TransferItem>> SourceItemsChanged { get; set; }
    [Parameter] public List<TransferItem>? TargetItems { get; set; }
    [Parameter] public EventCallback<List<TransferItem>> TargetItemsChanged { get; set; }
    [Parameter] public string? SourceTitle { get; set; }
    [Parameter] public string? TargetTitle { get; set; }
    [Parameter] public EventCallback<TransferChangeEventArgs> OnChange { get; set; }
    [Parameter] public bool ShowSearch { get; set; }
    /// <summary>When true (default), each panel header shows a select-all
    /// checkbox that toggles every enabled, currently-visible (filtered) item in
    /// that panel. The checkbox reflects an indeterminate state when only some
    /// items are selected.</summary>
    [Parameter] public bool ShowSelectAll { get; set; } = true;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly HashSet<string> _selectedSource = [];
    private readonly HashSet<string> _selectedTarget = [];
    private string _sourceSearch = "";
    private string _targetSearch = "";

    private string CssClass => Cx.Merge("flex items-start gap-3", Class);

    /// <summary>Reconcile the internal selection sets against the live Items on
    /// every parameter change. A parent that refreshes SourceItems/TargetItems
    /// (sort/filter/add/remove, or a same-content replace) must not leave behind
    /// "ghost" selections that inflate the header count or skew select-all.
    /// Guarded against the empty→refill flicker: an empty (or null) incoming
    /// list does NOT prune, so an in-progress selection survives a transient
    /// empty load rather than being silently wiped.</summary>
    protected override void OnParametersSet()
    {
        PruneSelection(_selectedSource, SourceItems);
        PruneSelection(_selectedTarget, TargetItems);
    }

    private static void PruneSelection(HashSet<string> selected, List<TransferItem>? items)
    {
        if (selected.Count == 0) return;
        // Empty/null incoming list is treated as a transient (loading) state —
        // keep the selection so an async refresh flicker can't clear it.
        if (items is not { Count: > 0 }) return;
        var valid = new HashSet<string>(items.Select(i => i.Value));
        selected.RemoveWhere(v => !valid.Contains(v));
    }

    private const string ButtonClass = "inline-flex items-center justify-center h-8 w-8 rounded-md border border-input bg-background hover:bg-accent hover:text-accent-foreground transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed";

    // Memoised filter lists. Same shape as PickList — re-run only when
    // the input list reference OR the search term changes. The dual-list
    // layout reads both Filtered* properties per render plus they're
    // touched from selection-state computations, so the previous getter
    // ran 4-8× per parent re-render. Cache collapses that to once per
    // actual input change.
    private List<TransferItem> _sourceFilterCache = [];
    private List<TransferItem>? _sourceFilterCacheBase;
    private string _sourceFilterCacheTerm = "";
    private List<TransferItem> _targetFilterCache = [];
    private List<TransferItem>? _targetFilterCacheBase;
    private string _targetFilterCacheTerm = "";

    private List<TransferItem> FilteredSourceItems
    {
        get
        {
            if (!ReferenceEquals(_sourceFilterCacheBase, SourceItems)
                || _sourceFilterCacheTerm != _sourceSearch)
            {
                _sourceFilterCacheBase = SourceItems;
                _sourceFilterCacheTerm = _sourceSearch;
                _sourceFilterCache = string.IsNullOrWhiteSpace(_sourceSearch)
                    ? SourceItems ?? new List<TransferItem>()
                    : (SourceItems ?? new List<TransferItem>())
                        .Where(i => i.Label.Contains(_sourceSearch, StringComparison.OrdinalIgnoreCase))
                        .ToList();
            }
            return _sourceFilterCache;
        }
    }

    private List<TransferItem> FilteredTargetItems
    {
        get
        {
            if (!ReferenceEquals(_targetFilterCacheBase, TargetItems)
                || _targetFilterCacheTerm != _targetSearch)
            {
                _targetFilterCacheBase = TargetItems;
                _targetFilterCacheTerm = _targetSearch;
                _targetFilterCache = string.IsNullOrWhiteSpace(_targetSearch)
                    ? TargetItems ?? new List<TransferItem>()
                    : (TargetItems ?? new List<TransferItem>())
                        .Where(i => i.Label.Contains(_targetSearch, StringComparison.OrdinalIgnoreCase))
                        .ToList();
            }
            return _targetFilterCache;
        }
    }

    private void OnSourceSearch(ChangeEventArgs e) => _sourceSearch = e.Value?.ToString() ?? "";
    private void OnTargetSearch(ChangeEventArgs e) => _targetSearch = e.Value?.ToString() ?? "";

    private static string ItemRowClass(bool disabled) =>
        disabled
            ? "flex items-center gap-2 px-2 py-1.5 rounded-md text-sm opacity-50 cursor-not-allowed"
            : "flex items-center gap-2 px-2 py-1.5 rounded-md cursor-pointer hover:bg-accent/50 transition-colors text-sm";

    private void ToggleSourceItem(string value, bool selected)
    {
        if (IsDisabled(SourceItems, value)) return;
        if (selected) _selectedSource.Add(value);
        else _selectedSource.Remove(value);
    }

    private void ToggleTargetItem(string value, bool selected)
    {
        if (IsDisabled(TargetItems, value)) return;
        if (selected) _selectedTarget.Add(value);
        else _selectedTarget.Remove(value);
    }

    private static bool IsDisabled(List<TransferItem>? items, string value)
        => items?.FirstOrDefault(i => i.Value == value)?.Disabled ?? false;

    // ---- Select-all (per panel, enabled + visible items only) ----
    private IEnumerable<TransferItem> SelectableSource => FilteredSourceItems.Where(i => !i.Disabled);
    private IEnumerable<TransferItem> SelectableTarget => FilteredTargetItems.Where(i => !i.Disabled);

    private bool SourceAllSelected
    {
        get
        {
            var selectable = SelectableSource.ToList();
            return selectable.Count > 0 && selectable.All(i => _selectedSource.Contains(i.Value));
        }
    }
    private bool SourcePartiallySelected
    {
        get
        {
            var count = SelectableSource.Count(i => _selectedSource.Contains(i.Value));
            return count > 0 && !SourceAllSelected;
        }
    }
    private bool TargetAllSelected
    {
        get
        {
            var selectable = SelectableTarget.ToList();
            return selectable.Count > 0 && selectable.All(i => _selectedTarget.Contains(i.Value));
        }
    }
    private bool TargetPartiallySelected
    {
        get
        {
            var count = SelectableTarget.Count(i => _selectedTarget.Contains(i.Value));
            return count > 0 && !TargetAllSelected;
        }
    }

    private void ToggleSelectAllSource(bool selected)
    {
        foreach (var item in SelectableSource)
        {
            if (selected) _selectedSource.Add(item.Value);
            else _selectedSource.Remove(item.Value);
        }
    }

    private void ToggleSelectAllTarget(bool selected)
    {
        foreach (var item in SelectableTarget)
        {
            if (selected) _selectedTarget.Add(item.Value);
            else _selectedTarget.Remove(item.Value);
        }
    }

    private async Task MoveToTarget()
    {
        var source = SourceItems ?? [];
        var target = TargetItems ?? [];
        // Only move rows that are BOTH selected AND currently visible (passing
        // the active search filter). A selected-but-filtered-out row stays put —
        // moving rows the user can no longer see is surprising. A selected row
        // the parent flipped to Disabled must not move either (it stays in the
        // source list, matching the contract that disabled rows can't move).
        var visible = new HashSet<string>(FilteredSourceItems.Select(i => i.Value));
        var moved = source.Where(i => _selectedSource.Contains(i.Value) && visible.Contains(i.Value) && !i.Disabled).ToList();
        var movedValues = new HashSet<string>(moved.Select(i => i.Value));
        var remaining = source.Where(i => !movedValues.Contains(i.Value)).ToList();
        target = [..target, ..moved];

        SourceItems = remaining;
        TargetItems = target;
        // Drop only the moved values from the selection; selected-but-filtered-out
        // rows keep their selection so they're still checked after the search clears.
        _selectedSource.RemoveWhere(movedValues.Contains);

        await SourceItemsChanged.InvokeAsync(SourceItems);
        await TargetItemsChanged.InvokeAsync(TargetItems);
        await OnChange.InvokeAsync(new TransferChangeEventArgs("right", moved));
    }

    private async Task MoveToSource()
    {
        var source = SourceItems ?? [];
        var target = TargetItems ?? [];
        // Only move rows that are BOTH selected AND currently visible (passing
        // the active search filter) — see MoveToTarget for rationale.
        var visible = new HashSet<string>(FilteredTargetItems.Select(i => i.Value));
        var moved = target.Where(i => _selectedTarget.Contains(i.Value) && visible.Contains(i.Value) && !i.Disabled).ToList();
        var movedValues = new HashSet<string>(moved.Select(i => i.Value));
        var remaining = target.Where(i => !movedValues.Contains(i.Value)).ToList();
        source = [..source, ..moved];

        SourceItems = source;
        TargetItems = remaining;
        _selectedTarget.RemoveWhere(movedValues.Contains);

        await SourceItemsChanged.InvokeAsync(SourceItems);
        await TargetItemsChanged.InvokeAsync(TargetItems);
        await OnChange.InvokeAsync(new TransferChangeEventArgs("left", moved));
    }

    /// <summary>A transfer row. A <see cref="Disabled"/> item can't be selected
    /// or moved (its checkbox is disabled and a select-all skips it) and renders
    /// dimmed.</summary>
    public record TransferItem(string Label, string Value, bool Disabled = false);
    public record TransferChangeEventArgs(string Direction, List<TransferItem> MovedItems);
}
